// pubspec.yaml:
//   dependencies:
//     isar: ^3.1.0+1
//     isar_flutter_libs: ^3.1.0+1
//     path_provider: ^2.1.4
//   dev_dependencies:
//     isar_generator: ^3.1.0+1
//     build_runner: ^2.4.13

// user.dart
import 'package:isar/isar.dart';
part 'user.g.dart';

@Collection()
class User {
  Id id = Isar.autoIncrement;                   // primary key

  @Index(unique: true, replace: true)
  late String email;                             // indexed for equality lookups

  @Index(caseSensitive: false)                   // case-insensitive text index
  late String name;

  DateTime? createdAt;

  @Enumerated(EnumType.name)                     // store enum as string
  UserStatus status = UserStatus.active;

  // Cross-collection link (like a foreign key, but bidirectional)
  final orders = IsarLinks<Order>();
}

enum UserStatus { active, banned, pending }

@Collection()
class Order {
  Id id = Isar.autoIncrement;

  @Index()
  late int totalCents;

  late DateTime createdAt;

  final owner = IsarLink<User>();                // singular link back
}

// Run: dart run build_runner build --delete-conflicting-outputs

// ============ Open + use the database ============
import 'package:isar/isar.dart';
import 'package:path_provider/path_provider.dart';

late final Isar isar;

Future<void> openIsar() async {
  final dir = await getApplicationDocumentsDirectory();
  isar = await Isar.open(
    [UserSchema, OrderSchema],                    // generated schemas
    directory: dir.path,
  );
}

// CRUD
final ada = User()
  ..email = 'ada@x.com'
  ..name = 'Ada Lovelace'
  ..createdAt = DateTime.now();

await isar.writeTxn(() async {
  await isar.users.put(ada);
});

// Query — fluent DSL, compile-time-verified
final recentActiveAdults = await isar.users
    .filter()
    .statusEqualTo(UserStatus.active)
    .and()
    .createdAtGreaterThan(DateTime(2026, 1, 1))
    .sortByCreatedAtDesc()
    .limit(20)
    .findAll();

// Reactive stream — auto-emits on writes
Stream<List<User>> topSpendersStream() {
  return isar.users
      .filter()
      .statusEqualTo(UserStatus.active)
      .watch(fireImmediately: true);
}

// Links — cross-collection relations without SQL FKs
final user = await isar.users.get(1);
await user!.orders.load();                       // fetch linked orders
print(user.orders.length);                       // typed collection

// Full-text search
final matches = await isar.users
    .filter()
    .nameStartsWith('ada')
    .findAll();
